/**
 * PressVideo — Lazy iframe injector + YouTube IFrame API.
 * Vanilla JS. No jQuery.
 */
(function () {
    'use strict';

    var CANVAS_ID  = 'pv-canvas';
    var AUTOPLAY_MS = 3000;

    var canvas, holder, spinner;
    var spinnerTimer     = null;
    var ytPlayer         = null;
    var ytApiReady       = !!(window.YT && window.YT.Player);
    var ytApiQueue       = [];
    var progressInterval = null;
    var currentYtId      = '';

    /* ── Load YouTube IFrame API ──────────────────────────────── */
    (function loadYtApi() {
        if (ytApiReady || document.getElementById('pv-yt-api')) return;
        var prev = window.onYouTubeIframeAPIReady;
        window.onYouTubeIframeAPIReady = function () {
            if (typeof prev === 'function') prev();
            ytApiReady = true;
            ytApiQueue.forEach(function (fn) { fn(); });
            ytApiQueue = [];
        };
        var s = document.createElement('script');
        s.id  = 'pv-yt-api';
        s.src = 'https://www.youtube.com/iframe_api';
        document.head.appendChild(s);
    }());

    function whenYtReady(fn) { ytApiReady ? fn() : ytApiQueue.push(fn); }

    /* ── Progress storage ─────────────────────────────────────── */
    function getProgress() {
        try { return JSON.parse(localStorage.getItem('pv_progress') || '{}'); } catch (e) { return {}; }
    }

    function saveProgress(ytId, sec, dur) {
        if (!ytId || !dur) return;
        var p    = getProgress();
        p[ytId]  = { sec: Math.floor(sec), dur: Math.floor(dur), pct: sec / dur, ts: Date.now() };
        try { localStorage.setItem('pv_progress', JSON.stringify(p)); } catch (e) {}
    }

    function startTracking(ytId) {
        stopTracking();
        currentYtId      = ytId;
        progressInterval = setInterval(function () {
            if (!ytPlayer) return;
            try {
                var sec = ytPlayer.getCurrentTime();
                var dur = ytPlayer.getDuration();
                if (dur > 0) {
                    saveProgress(ytId, sec, dur);
                    canvas.dispatchEvent(new CustomEvent('pv:progress-updated', {
                        bubbles: false,
                        detail: { youtubeId: ytId, sec: sec, dur: dur, pct: sec / dur }
                    }));
                }
            } catch (e) {}
        }, 5000);
    }

    function stopTracking() {
        if (progressInterval) { clearInterval(progressInterval); progressInterval = null; }
        currentYtId = '';
    }

    /* ── Init ─────────────────────────────────────────────────── */
    function init() {
        canvas  = document.getElementById(CANVAS_ID);
        if (!canvas) return;
        holder  = canvas.querySelector('.pv-iframe-holder');
        spinner = canvas.querySelector('.pv-spinner');

        canvas.addEventListener('pv:opened', onOpen);
        canvas.addEventListener('pv:closed', onClose);

        canvas.addEventListener('pv:seek-to', function (e) {
            var sec = (e.detail && e.detail.seconds) || 0;
            if (ytPlayer) { try { ytPlayer.seekTo(sec, true); } catch (err) {} }
        });

        canvas.addEventListener('pv:set-speed', function (e) {
            var rate = (e.detail && e.detail.rate) || 1;
            if (ytPlayer) { try { ytPlayer.setPlaybackRate(rate); } catch (err) {} }
        });

        // Music mode: pause/resume from mini-bar controls
        canvas.addEventListener('pv:pause-player', function () {
            if (ytPlayer) { try { ytPlayer.pauseVideo(); } catch (e) {} }
        });
        canvas.addEventListener('pv:resume-player', function () {
            if (ytPlayer) { try { ytPlayer.playVideo(); } catch (e) {} }
        });

        // Music mode: seek to percentage of total duration
        canvas.addEventListener('pv:seek-pct', function (e) {
            var pct = (e.detail && e.detail.pct) || 0;
            if (!ytPlayer) return;
            try {
                var dur = ytPlayer.getDuration();
                if (dur > 0) ytPlayer.seekTo(dur * pct, true);
            } catch (err) {}
        });
    }

    /* ── Open: create YT.Player ───────────────────────────────── */
    function onOpen() {
        if (!holder) return;
        var embedUrl = holder.dataset.embedUrl;
        if (!embedUrl || holder.dataset.loaded) return;
        showSpinner();

        var url  = new URL(embedUrl.replace('watch?v=', 'embed/'));
        var ytId = url.pathname.split('/').pop().split('?')[0];
        if (!ytId) { hideSpinner(); return; }

        if (ytPlayer) { try { ytPlayer.destroy(); } catch (e) {} ytPlayer = null; }

        var div        = document.createElement('div');
        div.id         = 'pv-yt-player';
        div.style.cssText = 'width:100%;height:100%';
        holder.innerHTML = '';
        holder.appendChild(div);

        spinnerTimer = setTimeout(function () { hideSpinner(); holder.dataset.loaded = '1'; }, AUTOPLAY_MS);

        // Snapshot saved progress + speed before async callback
        var pdata      = getProgress()[ytId] || {};
        var savedSpeed = parseFloat(localStorage.getItem('pv_speed') || '1') || 1;

        whenYtReady(function () {
            var el = document.getElementById('pv-yt-player');
            if (!el || !el.isConnected) return;
            try {
                ytPlayer = new YT.Player('pv-yt-player', {
                    videoId:    ytId,
                    width:      '100%',
                    height:     '100%',
                    playerVars: { autoplay: 1, rel: 0, modestbranding: 1, playsinline: 1 },
                    events: {
                        onReady: function () {
                            clearTimeout(spinnerTimer);
                            hideSpinner();
                            holder.dataset.loaded = '1';

                            var iframe = holder.querySelector('iframe');
                            if (iframe) {
                                iframe.style.width   = '100%';
                                iframe.style.height  = '100%';
                                iframe.style.border  = 'none';
                                iframe.style.display = 'block';
                                var titleEl = canvas.querySelector('.pv-title');
                                iframe.title = titleEl ? (titleEl.textContent || 'Video') : 'Video';
                            }

                            // Apply saved playback speed
                            if (savedSpeed !== 1) {
                                try { ytPlayer.setPlaybackRate(savedSpeed); } catch (e) {}
                            }

                            // Start progress tracking
                            startTracking(ytId);

                            // Signal offcanvas controller with saved resume data
                            canvas.dispatchEvent(new CustomEvent('pv:player-ready', {
                                bubbles: false,
                                detail: {
                                    youtubeId: ytId,
                                    savedSec:  pdata.sec || 0,
                                    savedPct:  pdata.pct || 0
                                }
                            }));
                        },
                        onStateChange: function (e) {
                            canvas.dispatchEvent(new CustomEvent('pv:player-state-changed', {
                                bubbles: false,
                                detail: { state: e.data }
                            }));
                            if (e.data === YT.PlayerState.ENDED) {
                                // Save full completion before firing ended event
                                if (currentYtId) {
                                    var p = getProgress();
                                    var ex = p[currentYtId] || {};
                                    if (ex.dur > 0) saveProgress(currentYtId, ex.dur, ex.dur);
                                }
                                canvas.dispatchEvent(new CustomEvent('pv:video-ended', { bubbles: false }));
                            }
                        }
                    }
                });
            } catch (err) {
                clearTimeout(spinnerTimer);
                hideSpinner();
            }
        });

        canvas.dispatchEvent(new CustomEvent('pv:iframe-ready', { bubbles: false, detail: { youtubeId: ytId } }));
    }

    /* ── Close: destroy player ────────────────────────────────── */
    function onClose() {
        stopTracking();
        clearTimeout(spinnerTimer);
        if (!holder) return;
        if (ytPlayer) { try { ytPlayer.destroy(); } catch (e) {} ytPlayer = null; }
        holder.innerHTML = '';
        delete holder.dataset.loaded;
        hideSpinner();
    }

    function showSpinner() { if (spinner) { spinner.removeAttribute('hidden'); spinner.style.display = ''; } }
    function hideSpinner() { if (spinner) { spinner.style.display = 'none'; } }

    if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
    else init();
}());
